const promptData = $('Build DM System Prompt').first().json;

const toMatch = output.match(/\*To:\*\s*(.+)/i);
const ccMatch = output.match(/\*CC:\*\s*(.+)/i);
const subjectMatch = output.match(/\*Subject:\*\s*(.+)/i);

// Not an email draft — pass through as plain text
if (!toMatch || !subjectMatch) {
  return [{ json: { ...($json), isDraft: false, blocks: null, fallbackText: output } }];
}

// Extract email from "Name (Title) <email>" or plain email
function extractEmail(line) {
  const angleMatch = line.match(/<([^>]+@[^>]+)>/);
  if (angleMatch) return angleMatch[1].trim();
  const parenMatch = line.match(/\(([^)]+@[^)]+)\)/);
  if (parenMatch) return parenMatch[1].trim();
  const plainMatch = line.match(/[\w.+-]+@[\w.-]+\.\w+/);
  if (plainMatch) return plainMatch[0].trim();
  return '';
}

const toEmail = extractEmail(toMatch[1]);
// Extract all emails from a line (for CC with multiple recipients)
function extractAllEmails(line) {
  const emails = [];
  const regex = /[\w.+-]+@[\w.-]+\.\w+/g;
  let m;
  while ((m = regex.exec(line)) !== null) {
    emails.push(m[0].trim());
  }
  return emails.join(',');
}
const ccEmail = ccMatch ? extractAllEmails(ccMatch[1]) : '';
const subject = subjectMatch[1].trim();

// Extract email body between the --- dividers (after Subject, before trailing ---)
let body = '';
if (subjectMatch) {
  const startIdx = output.indexOf(subjectMatch[0]) + subjectMatch[0].length;
  let afterSubject = output.substring(startIdx);

  // The email body is typically wrapped in --- dividers
  // Find the opening --- after subject
  const openDivider = afterSubject.indexOf('---');
  if (openDivider > -1) {
    const bodyStart = openDivider + 3;
    // Find the closing --- after the body
    const closeDivider = afterSubject.indexOf('\n---', bodyStart);
    if (closeDivider > -1) {
      body = afterSubject.substring(bodyStart, closeDivider).trim();
    } else {
      // No closing divider — use end markers as fallback
      body = afterSubject.substring(bodyStart).trim();
    }
  } else {
    // No dividers at all — take everything after subject
    body = afterSubject.trim();
  }

  // Trim at any Slack UI chrome that leaked through
  const uiMarkers = [
    '\n_Reply in this thread',
    '\n_Reply to adjust',
    '\n:warning:',
    '\n\u26a0',
    '\n*Next Steps',
  ];
  for (const marker of uiMarkers) {
    const idx = body.indexOf(marker);
    if (idx > -1) body = body.substring(0, idx).trim();
  }

  // Clean up any remaining --- at start/end
  body = body.replace(/^---\s*/, '').replace(/\s*---$/, '').trim();
}

// Strip Slack mrkdwn for plain-text email
const plainBody = body
  .replace(/\*\*([^*]+)\*\*/g, '$1')  // **double bold** (Markdown)
  .replace(/\*([^*]+)\*/g, '$1')       // *single bold* (Slack mrkdwn)
  .replace(/_([^_]+)_/g, '$1')          // _italic_
  .replace(/~([^~]+)~/g, '$1')          // ~strikethrough~
  .replace(/:[a-z0-9_+-]+:/g, '')       // :emoji: codes
  .replace(/•/g, '-')                    // bullet chars
  .replace(/- \*\*/g, '- ')             // leftover bold after bullets
  .replace(/\*\*$/gm, '')               // trailing bold markers
  .replace(/\n{3,}/g, '\n\n')           // excess newlines
  .trim();

// Build Gmail compose deep link
let composeUrl = '';
if (toEmail || subject) {
  const params = ['view=cm', 'fs=1'];
  if (toEmail) params.push('to=' + encodeURIComponent(toEmail));
  if (ccEmail) params.push('cc=' + encodeURIComponent(ccEmail));
  if (subject) params.push('su=' + encodeURIComponent(subject));
  if (plainBody) params.push('body=' + encodeURIComponent(plainBody));
  composeUrl = 'https://mail.google.com/mail/?' + params.join('&');
}

// Truncate if too long (browser URL limit ~8000 chars for Chrome)
const MAX_URL = 7500;
if (composeUrl.length > MAX_URL) {
  const truncBody = plainBody.substring(0, 2000) + '\n\n[... see full draft in Slack thread]';
  const params2 = ['view=cm', 'fs=1'];
  if (toEmail) params2.push('to=' + encodeURIComponent(toEmail));
  if (ccEmail) params2.push('cc=' + encodeURIComponent(ccEmail));
  if (subject) params2.push('su=' + encodeURIComponent(subject));
  params2.push('body=' + encodeURIComponent(truncBody));
  composeUrl = 'https://mail.google.com/mail/?' + params2.join('&');
}

