    return `\u2022 ${t.description}` + (t.owner ? ` \u2014 _${t.owner}_` + roleBadge : '') + durationBadge + (t.due_hint ? ` \u00b7 ${t.due_hint}` : '');
  }).join('\n');
  blocks.push({ type: "section", text: { type: "mrkdwn", text: `*Action Items* (saved to CRM)\n${taskText}` } });
}

if ((!recap.keyDecisions || recap.keyDecisions.length === 0) && (!recap.tasks || recap.tasks.length === 0)) {
  blocks.push({ type: "section", text: { type: "mrkdwn", text: "_No key decisions or action items were captured for this meeting._" } });
}

blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: "Tasks and recap saved to CRM \u2022 Use PeopleGlass to review or modify \u2022 Reply in this thread to discuss" }] });

return [{ json: { threadBlocks: JSON.stringify(blocks), threadTs: sendResult.ts, channelId: sendResult.channel, assistantName, assistantEmoji } }];

// No meeting found — update the generating message with the error
const data = $('Recap Parse Meetings').first().json;
const genMsg = $('Send Recap Generating').first().json;

return [{ json: {
  channel: genMsg.channel,
  ts: genMsg.ts,
  text: data.assistantEmoji + ' ' + data.responseText,
  username: data.assistantName,
  icon_emoji: data.assistantEmoji,
} }];

const data = $('Route by State').first().json;
const text = (data.text || '').trim();

const accountArg = text
  .replace(/^tasks?\s*/i, '')
  .replace(/\b(my|the|a|for|with|about|on|please|sf|salesforce)\b/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const requestId = 'req_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
const ur = data.userRecord || {};

return [{ json: {
  ...data,
  hasAccount: true,
  isMyTasks: !accountArg,
  accountArg: accountArg || 'My Tasks',
  action: accountArg ? 'get_tasks' : 'get_my_tasks',
  requestId,
  userEmail: ur.email || '',
  assistantName: ur.assistant_name || data.assistantName || 'Aria',
  assistantEmoji: ur.assistant_emoji || data.assistantEmoji || ':robot_face:',
}}];

const data = $('Route by State').first().json;
const dmChannel = $json.channel?.id || $json.channel;
const sub = data.subRoute || 'calibrate';
const companyName = data.companyName || '';
const name = data.assistantName || data.assistant_name || 'Aria';
const emoji = data.assistantEmoji || data.assistant_emoji || ':robot_face:';
let text = '';
if (sub === 'calibrate') {
  text = ':mag: Running ICP calibration \u2014 analyzing won vs lost patterns... this takes 3-5 minutes.';
} else if (sub === 'targets') {
  text = ':mag: Finding target accounts matching your ICP... give me about 30 seconds.';
} else {
  text = ':mag: Comparing *' + companyName + '* against your winning pattern... give me about 30 seconds.';
}
return [{ json: { channel: dmChannel, text, username: name, icon_emoji: emoji } }];

const data = $('Route by State').first().json;
const user = $('Lookup User').first().json;
const dmChannel = $('Open Bot DM (ICP)').first().json.channel?.id || $('Open Bot DM (ICP)').first().json.channel;
const sub = data.subRoute || 'calibrate';
let mode = sub === 'targets' ? 'targets' : sub === 'compare' ? 'compare' : 'calibrate';
let companyName = data.companyName || '';
const repName = (user.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase());
return [{ json: {
  mode, companyName, userId: user.id,
  slackUserId: user.slack_user_id || data.userId,
  email: user.email, channelId: dmChannel,
  assistantName: user.assistant_name || 'Aria',
  assistantEmoji: user.assistant_emoji || ':robot_face:',
  assistantPersona: user.assistant_persona || '',
  digestScope: user.digest_scope || 'my_deals',
  repName,
} }];

const data = $('Recap Parse Output OD').first().json;
const recap = data.recap;
const m = data.meeting;

const description = [
  'Summary:', recap.summary, '',
  recap.keyDecisions && recap.keyDecisions.length > 0
    ? 'Key Decisions:\n' + recap.keyDecisions.map(d => '\u2022 ' + d).join('\n') : '',
  '',
  recap.tasks && recap.tasks.length > 0
    ? 'Action Items:\n' + recap.tasks.map(t =>
        '\u2022 ' + t.description + (t.owner ? ' \u2014 ' + t.owner : '') +
        (t.due_hint ? ' \u00b7 ' + t.due_hint : '')
      ).join('\n') : '',
].filter(Boolean).join('\n');

const activityPayload = {
  action: 'log_activity',
  salesforce_object: 'Event',
  fields: {
    Subject: m.subject || 'Customer Meeting',
    Description: description,
    ActivityDate: new Date().toLocaleDateString('en-CA', { timeZone: 'America/Los_Angeles' }),
    meeting_category: recap.meetingCategory || null,
    cs_category: recap.csCategory || null,
  },
  context: {
    user_email: data.email || '',
    account_name: m.accountName || '',
    activity_uid: m.activityUid || '',
    prepend_description: true,
  }
};

const now = new Date();
const ptNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/Los_Angeles' }));
function parseDueDate(hint) {
  const h = (hint || '').toLowerCase();
  if (h.includes('today') || h.includes('asap')) return ptNow.toISOString().split('T')[0];
  if (h.includes('tomorrow')) { const d = new Date(ptNow.getTime() + 86400000); return d.toISOString().split('T')[0]; }
  if (h.includes('friday') || h.includes('this week') || h.includes('end of week')) {
    const d = new Date(ptNow); d.setDate(d.getDate() + ((5 - d.getDay() + 7) % 7 || 7)); return d.toISOString().split('T')[0];
  }
  if (h.includes('next week')) { const d = new Date(ptNow.getTime() + 7 * 86400000); return d.toISOString().split('T')[0]; }
  const dateMatch = (hint || '').match(/(\w+ \d{1,2}(?:,? \d{4})?)/);
  if (dateMatch) { const parsed = new Date(dateMatch[1]); if (!isNaN(parsed.getTime())) return parsed.toISOString().split('T')[0]; }
  const d = new Date(ptNow.getTime() + 7 * 86400000); return d.toISOString().split('T')[0];
}

const taskPayloads = (recap.tasks || []).slice(0, 5).map(t => ({
  action: 'create_task', salesforce_object: 'Task',
  fields: {
    Subject: (t.description || '').substring(0, 255),
    Description: 'From meeting: ' + (m.subject || '') + ' with ' + (m.accountName || '') +
      '\nAssigned to: ' + (t.owner || '') + (t.assignee_role ? ' (' + t.assignee_role + ')' : '') +
      '\nEstimated duration: ' + (t.duration_minutes || 30) + ' minutes',
    ActivityDate: parseDueDate(t.due_hint),
    Status: 'Not Started', Priority: 'Normal',
    TaskDuration: parseInt(t.duration_minutes) || 30,
    Category: t.task_category || '',
  },
  context: {
    user_email: '', account_name: m.accountName || '',
    meeting_subject: m.subject || '',
    assignee_name: t.owner || '', assignee_email: t.owner_email || '',
    assignee_role: t.assignee_role || '',
  }
}));

return [{ json: { ...data, activityPayload, taskPayloads, taskCount: taskPayloads.length } }];

const data = $('Build Auto-Save OD').first().json;
const payloads = data.taskPayloads || [];
if (payloads.length === 0) return [{ json: { skip: true } }];
return payloads.map(p => ({ json: { webhook_payload: p } }));

const data = $('Recap Parse Output OD').first().json;
const m = data.meeting || {};
const requestId = 'res_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

return [{ json: {
  ...data,
  resolutionRequestId: requestId,
  resolutionPayload: {
    action: 'get_tasks_resolution',
    account_name: m.accountName || '',
    user_email: data.email || '',
    callback_url: 'https://scottai.trackslife.com/webhook/task-resolution-callback',
    request_id: requestId,
  },
  resolutionContext: {
    channel_id: data.channelId || '',
    assistant_name: data.assistantName || 'Aria',
    assistant_emoji: data.assistantEmoji || ':robot_face:',
    mode: 'recap',
    account_name: m.accountName || '',
  }
}}];

const body = $('Slack Events Webhook').first().json.body;
const headers = $('Slack Events Webhook').first().json.headers || {};

// Drop Slack retry deliveries
if (headers['x-slack-retry-num'] && parseInt(headers['x-slack-retry-num']) > 0) {
  return [];
}

const event = body.event || {};

// Layer 1: Classic bot indicators
const hasClassicBotIndicator = !!(event.bot_id || event.subtype || event.bot_profile || event.app_id);

// Layer 2: Self-message check via authorizations
const auths = body.authorizations || [];
const botUserId = auths.length > 0 ? auths[0].user_id : null;
const isSelfMessage = !!(botUserId && event.user === botUserId);

// Layer 3: Text-based bot message detection (stops feedback loops)
const text = (event.text || '').trim();
const isBotText = text.startsWith(':hourglass_flowing_sand:') ||
  text.startsWith('Sorry, I was unable to generate') ||
  text === '';

// Layer 4: No user = non-human event
const noUser = !event.user;

const isBot = hasClassicBotIndicator || isSelfMessage || (isBotText && !event.user) || noUser;

return [{
  json: {
    eventType: event.type,
    channelType: event.channel_type || null,
    userId: event.user,
    channelId: event.channel || null,
    text: text,
    ts: event.ts,
    eventId: body.event_id,
    teamId: body.team_id,
    isBot,
    tab: event.tab || null,
    threadTs: event.thread_ts || null,
    isThreadReply: !!event.thread_ts,
    _debug_botUserId: botUserId,
    _debug_hasClassic: hasClassicBotIndicator,
    _debug_isSelf: isSelfMessage,
    _debug_isBotText: isBotText,
    _debug_eventUser: event.user || null,
    _debug_authCount: auths.length
  }
}];

const event = $('Extract Event Data').first().json;
const user = $('Lookup User').first().json;
const text = event.text;
const userId = event.userId;

let userExists = !!(user && user.id);
let state = userExists ? (user.onboarding_state || 'new') : null;
let route = 'unknown';
let subRoute = 'help';

if (!userExists) {
  route = 'new_user';
} else if (state === 'new') {
  route = 'send_greeting';
} else if (state === 'awaiting_name') {
  route = 'capture_name';
} else if (state === 'awaiting_emoji') {
  route = 'capture_emoji';
} else if (state === 'complete') {
  const lower = text.toLowerCase();


  // --- Pending action routing (announcement confirmation) ---
  const pendingRaw = $('Check Pending Action').first().json;
  const hasPending = Array.isArray(pendingRaw)
    ? pendingRaw.length > 0 && pendingRaw[0].id
    : (pendingRaw && pendingRaw.id);

  if (hasPending) {
    if (lower === 'send') route = 'confirm_announce';
    else if (lower === 'cancel') route = 'cancel_announce';
    else if (lower.startsWith('announce:') || lower.startsWith('announce ')) route = 'cmd_announce';
    else route = 'expire_pending';
  }

  // --- Pass 1/2/3 only run if no route set by pending action check ---
  if (route === 'unknown') {
  // --- Pass 1: Exact command matching (keyword at start of text) ---
  if (lower.startsWith('announce:') || lower.startsWith('announce ')) route = 'cmd_announce';
  else if (lower.startsWith('rename ')) route = 'cmd_rename';
  else if (lower.startsWith('emoji ')) route = 'cmd_emoji';
  else if (lower.startsWith('persona ')) route = 'cmd_persona';
  else if (lower === 'scope' || lower.startsWith('scope ')) route = 'cmd_scope';
  else if (lower === 'focus' || lower.startsWith('focus ')) route = 'cmd_focus';
  else if (lower === 'silence' || lower === 'silent' || lower === 'silent accounts' || lower.startsWith('silence check')) {
      route = 'cmd_silence';
    } else if (lower === 'brief' || lower.startsWith('brief ')) route = 'cmd_brief';
  else if (lower === 'meet' || lower.startsWith('meet ') || lower.startsWith('meeting brief ') || lower.startsWith('prep ')) route = 'cmd_meet';
  else if (lower === 'icp') { route = 'cmd_icp'; subRoute = 'calibrate'; }
  else if (lower === 'icp targets') { route = 'cmd_icp'; subRoute = 'targets'; }
  else if (lower.startsWith('icp ')) { route = 'cmd_icp'; subRoute = 'compare'; }
  else if (lower === 'insights' || lower.startsWith('insights ')) route = 'cmd_insights';
  else if (/\b(bbr|pbr)\b/i.test(lower)) route = 'cmd_bbr';
  else if (lower === 'presentation' || lower.startsWith('presentation ')) route = 'cmd_presentation';
  else if (lower === 'stakeholders' || lower.startsWith('stakeholders ')) {
    route = 'cmd_other'; subRoute = 'stakeholders';
  }
  else if (lower === 'followup' || lower.startsWith('followup ') || lower.startsWith('follow-up ') || lower.startsWith('follow up ')) {
    route = 'cmd_recap';
  }
  else if (lower === 'tasks' || lower === 'task' || lower.startsWith('tasks ')) route = 'cmd_tasks';
  else if (lower === 'recap' || lower.startsWith('recap ')) route = 'cmd_recap';
  else if (lower.startsWith('more ') || (lower.startsWith('help ') && lower !== 'help')) {
    route = 'cmd_other'; subRoute = 'more_help';
  } else {
    // --- Pass 2: Fuzzy keyword matching (keyword anywhere in text) ---
    if (/\b(presentation|slide|slides|deck)\b/.test(lower)) route = 'cmd_presentation';
    else if (/\b(business\s+review)\b/.test(lower)) route = 'cmd_bbr';
    else if (/\b(brief|briefing|digest)\b/.test(lower)) route = 'cmd_brief';
    else if (/\b(meet(?:ing)?\s+(?:brief|prep)|prep\s+(?:me|for))\b/i.test(lower)) route = 'cmd_meet';
    else if (/\binsights?\b/.test(lower)) route = 'cmd_insights';
    else if (/\b(stakeholder|stakeholders|who\s+(should|am|are)\s+I?\s*(be\s+)?talk)/i.test(lower)) {
      route = 'cmd_other'; subRoute = 'stakeholders';
    }
    else if (/\b(follow[\s-]?up|draft\s+(a\s+)?(email|message|note))\b/i.test(lower)) {
      route = 'cmd_recap';
    }
    else if (/\bmy tasks\b/i.test(lower)) route = 'cmd_tasks';
    else if (/\b(recap|meeting\s+recap)\b/i.test(lower)) route = 'cmd_recap';
    else {
      // --- Pass 3: Meta commands and fallback ---
      route = 'cmd_other';
      if (lower === 'stop digest' || lower === 'pause digest') subRoute = 'stop_digest';
      else if (lower === 'resume digest' || lower === 'start digest') subRoute = 'resume_digest';
      else if (lower === 'stop briefs' || lower === 'pause briefs' || lower === 'stop meeting briefs') subRoute = 'stop_briefs';
      else if (lower === 'start briefs' || lower === 'resume briefs' || lower === 'start meeting briefs') subRoute = 'resume_briefs';
      else if (lower === 'stop followups' || lower === 'pause followups' || lower === 'stop follow-ups') subRoute = 'stop_followups';
      else if (lower === 'start followups' || lower === 'resume followups' || lower === 'start follow-ups') subRoute = 'resume_followups';
      else if (lower === 'stop tips' || lower === 'pause tips') subRoute = 'stop_tips';
      else if (lower === 'resume tips' || lower === 'start tips') subRoute = 'resume_tips';
      else if (lower === 'stop announcements') subRoute = 'stop_announcements';
      else if (lower === 'resume announcements' || lower === 'start announcements') subRoute = 'resume_announcements';
      else if (lower === 'help') subRoute = 'help';
      else subRoute = 'unrecognized';
    }
  }
  } // end route === 'unknown' guard
}

let assistantName = (userExists && user.assistant_name) ? user.assistant_name : 'Your Assistant';
let assistantEmoji = (userExists && user.assistant_emoji) ? user.assistant_emoji : ':robot_face:';

return [{
  json: {
    route, subRoute, userId, text,
    companyName: (text || '').toLowerCase().startsWith('icp ') && subRoute === 'compare' ? text.replace(/^icp\s+/i, '').trim() : '',
    channelId: event.channelId,
    teamId: event.teamId,
    userRecord: userExists ? user : null,
    dbUserId: userExists ? user.id : null,
    organizationId: userExists ? user.organization_id : null,
    assistantName, assistantEmoji, state
  }
}];

