  'technical': 'technical', 'se': 'technical', 'solutions': 'technical', 'poc': 'technical', 'engineering': 'technical',
  'executive': 'executive', 'exec': 'executive', 'leadership': 'executive', 'strategic': 'executive', 'ceo': 'executive'
};

const focusLabels = {
  'revenue':   'Revenue — new logo & net new ARR',
  'retention': 'Retention — renewals & existing customers',
  'technical': 'Technical — POC stage & SE view',
  'executive': 'Executive — strategic portfolio overview'
};

let newFocus = null;
let needsUpdate = false;
let responseText = '';

if (!focusArg || focusArg === 'status' || focusArg === 'show' || focusArg === '?') {
  responseText = `Your current briefing focus is *${focusLabels[currentFocus] || currentFocus}*.\n\nChange it with:\n• \`focus revenue\` — new logo and net new ARR\n• \`focus retention\` — renewals and existing customers only\n• \`focus technical\` — POC stage and SE view\n• \`focus executive\` — strategic portfolio overview`;
} else {
  newFocus = focusMap[focusArg] || null;
  if (!newFocus) {
    responseText = `*"${focusArg}"* isn't a recognised focus. Options:\n• \`focus revenue\` — new logo and net new ARR\n• \`focus retention\` — renewals and existing customers only\n• \`focus technical\` — POC stage and SE view\n• \`focus executive\` — strategic portfolio overview`;
  } else if (newFocus === currentFocus) {
    responseText = `Your focus is already set to *${focusLabels[newFocus]}* — nothing to change.`;
  } else {
    needsUpdate = true;
    responseText = `Done. Your briefing focus is now *${focusLabels[newFocus]}*.\n\nType \`brief\` to generate a digest with your updated focus.`;
  }
}

return [{
  json: {
    userId: input.dbUserId,
    channelId: input.channelId,
    newFocus: newFocus || currentFocus,
    needsUpdate,
    responseText,
    assistantName,
    assistantEmoji
  }
}];

const orgId = $('Lookup Default Org').first().json.id;
const userInfo = $('Get Slack User Info').first().json;
const profile = $('Extract Slack Profile').first().json;
const routeData = $('Route by State').first().json;

return [{
  json: {
    slack_user_id: routeData.userId,
    email: userInfo.user.profile.email,
    organization_id: orgId,
    department: profile.extractedDepartment,
    division: profile.extractedDivision,
    digest_scope: profile.derivedDigestScope,
    onboarding_state: 'awaiting_name'
  }
}];

const data = $('Route by State').first().json;
const text = (data.text || '').trim();
const accountName = text
  .replace(/^presentation\s+/i, '')
  .replace(/\b(bbr|pbr|business\s+review|backstory\s+business\s+review|for|with|about|on|create|make|generate|build|a|the|deck|slide|presentation)\b/gi, ' ')
  .replace(/\s+/g, ' ').trim();
return [{ json: {
  ...data, bbrAccount: accountName,
  isValid: accountName.length > 0,
  responseText: accountName.length > 0 ? '' : data.assistantEmoji + ' Please include the company name. Example:\n`BBR for AMD`'
}}];

return [{ json: {
  channelId: $('Parse BBR').first().json.channelId,
  bbrAccount: $('Parse BBR').first().json.bbrAccount,
  assistantName: $('Parse BBR').first().json.assistantName,
  assistantEmoji: $('Parse BBR').first().json.assistantEmoji,
  thinkingTs: $('Send BBR Thinking').first().json.ts
}}];

// Gather data from Extract Event Data and Check Active Conversation
const event = $('Extract Event Data').first().json;
const conversation = $('Check Active Conversation').first().json;

return [{
  json: {
    channelId: event.channelId,
    threadTs: event.threadTs,
    userId: event.userId,
    messageText: event.text,
    conversationId: conversation.id,
    conversationStatus: conversation.status,
    slackUserName: event.userId
  }
}];

const routeData = $('Route by State').first().json;

// Guard: empty text = bot self-message that slipped through filters
if (!routeData.text || routeData.text.trim().length === 0) {
  return [{ json: { ...routeData, userMessage: '', systemPrompt: '', skipAgent: true,
    channelId: routeData.channelId, thinkingText: '',
    assistantName: routeData.assistantName || 'Aria',
    assistantEmoji: routeData.assistantEmoji || ':robot_face:' } }];
}

const user = routeData.userRecord || {};

const assistantName = routeData.assistantName || 'Aria';
const assistantEmoji = routeData.assistantEmoji || ':robot_face:';
const assistantPersona = (user.assistant_persona) || 'direct, action-oriented, conversational';
const repName = user.name || (user.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || 'there';
const subRoute = routeData.subRoute || 'unrecognized';

// ── Common footer: available commands (only mentioned when relevant) ──
const commandsBlock = [
  '',
  '**AVAILABLE COMMANDS:**',
  'If the user seems to be asking about any of the following, let them know they can use these commands by typing them directly in this DM:',
  '',
  '_Workflow triggers:_',
  '- `presentation <topic> for <account>` — create a presentation',
  '- `bbr <account>` or `pbr <account>` — generate a Business Review presentation',
  '- `brief` — get an on-demand sales digest (also: `brief risk`, `brief momentum`)',
  '- `insights` — pipeline intelligence analysis (also: `insights stalled`, `insights risk`)',
  '- `stakeholders <account>` — stakeholder map and engagement analysis',
  '- `followup <account>` — draft a follow-up email after a meeting',
  '',
  '_Settings:_',
  '- `rename <name>` — change assistant name',
  '- `emoji <emoji>` — change assistant emoji',
  '- `persona <description>` — change assistant personality',
  '- `scope my_deals|team_deals|top_pipeline` — change briefing scope',
  '- `focus retention|revenue|technical|executive` — change digest focus area',
  '- `stop digest` / `resume digest` — toggle morning briefings',
  '- `stop tips` / `resume tips` — toggle feature education tips',
  '- `stop announcements` / `resume announcements` — toggle new feature announcements',
  '- `help` — see the full command list',
  '',
  'Only mention these commands if they are relevant to what the user is asking about. Do not list all commands unprompted.',
].join('\n');

let systemPrompt;

if (subRoute === 'stakeholders') {
  // ── Stakeholder-focused prompt ──
  systemPrompt = [
    'You are ' + assistantName + ', a personal sales assistant for ' + repName + '.',
    '',
    'Your personality: ' + assistantPersona,
    '',
    'You have access to Backstory MCP tools which give you CRM data, account activity, engagement scores, and contact information.',
    '',
    '**STAKEHOLDER ANALYSIS MODE**',
    '',
    'The user wants a stakeholder analysis. Use Backstory MCP tools to:',
    '1. Find the account and its key contacts/people engaged',
    '2. Check engagement history for each contact (last activity date, type, frequency)',
    '3. Identify engagement trends (rising, steady, declining, silent)',
    '4. Spot coverage gaps (missing roles like exec sponsor, procurement, technical lead)',
    '',
    '**FORMAT YOUR RESPONSE like this (Slack mrkdwn):**',
    '',
    ':mag: *Stakeholder Map — {Account Name}*',
    '',
    '*Active Contacts:*',
    '• *Name* — Role — Last: {type} on {date} — :chart_with_upwards_trend: Rising',
    '',
    '*Gone Quiet:*',
    '• *Name* — Role — Last: {type} on {date} — :warning: {N} days silent',
    '',
    '*Coverage Gaps:*',
    '• Any notable missing roles or under-engaged titles',
    '',
    '*Recommendation:*',
    'One specific, actionable suggestion for who to re-engage and why.',
    '',
    '**RULES:**',
    '- Use Slack formatting: *bold*, _italic_, `code`',
    '- Use emoji indicators: :chart_with_upwards_trend: (rising), :arrow_right: (steady), :chart_with_downwards_trend: (declining), :warning: (quiet 10+ days), :red_circle: (silent 21+ days)',
    '- Keep total response under 3000 characters',
    '- Do NOT use ### headers — use *bold* for section titles',
    '- If the account is not found, say so clearly',
    '- If no specific account is mentioned, ask the user which account they want to analyze',
    commandsBlock,
  ].join('\n');

} else if (subRoute === 'followup') {
  // ── Follow-up email draft prompt ──
  const todayStr = new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  systemPrompt = [
    'You are ' + assistantName + ', a personal sales assistant for ' + repName + '.',
    '',
    'Your personality: ' + assistantPersona,
    '',
    'You have access to Backstory MCP tools which give you CRM data, account activity, meeting details, and engagement data.',
    '',
    '**FOLLOW-UP EMAIL DRAFT MODE**',
    '',
    "TODAY IS " + todayStr + ". Remember this date — it is critical for determining meeting recency.",
    '',
    '## TODAY\'S MEETINGS (from calendar/Query API — NOT dependent on transcript ingestion):',
    '',
    (() => {
      try {
        const csv = $('DM Fetch Today Meetings').first().json.data || '';
        if (!csv || csv.trim().length < 10) return '_No meeting data available from Query API._';
        const lines = csv.trim().split('\n');
        if (lines.length < 2) return '_No meetings found in the last 24 hours._';

        // Parse CSV
        const hdrs = [];
        let hField = '', hInQ = false;
        for (const ch of lines[0]) {
          if (ch === '"') { hInQ = !hInQ; continue; }
          if ((ch === ',' || ch === '\t') && !hInQ) { hdrs.push(hField.trim()); hField = ''; continue; }
          hField += ch;
        }
        hdrs.push(hField.trim());

        function parseRow(line) {
          const vals = []; let f = '', q = false;
          for (let i = 0; i < line.length; i++) {
            const c = line[i];
            if (c === '"') { q = !q; continue; }
            if (c === '[') { q = true; continue; }
            if (c === ']') { q = false; continue; }
            if (c === ',' && !q) { vals.push(f.trim()); f = ''; continue; }
            f += c;
          }
          vals.push(f.trim());
          return vals;
        }

        function getCol(row, name) {
          const idx = hdrs.findIndex(h => h.toLowerCase().includes(name.toLowerCase()));
          return idx >= 0 ? (row[idx] || '') : '';
        }

        const tz = 'America/Los_Angeles';
        const meetingLines = [];
        for (let i = 1; i < Math.min(lines.length, 100); i++) {
          if (!lines[i].trim()) continue;
          const row = parseRow(lines[i]);
          const subject = getCol(row, 'Subject') || '[no subject]';
          const account = getCol(row, 'Account') || '[unmatched]';
          const ts = getCol(row, 'date') || getCol(row, 'timestamp');
          const participants = getCol(row, 'Email') || '';
          let timeStr = '';
          try {
            const d = new Date(ts);
            timeStr = d.toLocaleTimeString('en-US', { timeZone: tz, hour: 'numeric', minute: '2-digit' });
          } catch(e) { timeStr = ts; }
          meetingLines.push('- ' + timeStr + ' | ' + account + ' | "' + subject + '" | Participants: ' + participants);
        }
        if (meetingLines.length === 0) return '_No external meetings found._';
        return meetingLines.join('\n');
      } catch(e) {
        return '_Could not fetch meeting data: ' + e.message + '_';
      }
    })(),
    '',
    'Use the meeting list above to identify which meeting the user is asking about.',
    'Even if MCP does not have transcript data yet, you KNOW these meetings happened.',
    'Draft based on the meeting title, account, and participants — add a note that details will improve once transcript data syncs.',
    '',
    '## CRITICAL: DATA LATENCY PROTOCOL',
    'Backstory transcript data takes 3-4 HOURS to appear after a meeting ends.',
    'When the user asks for a followup, they almost certainly mean a meeting that happened TODAY.',
    '',
    '**YOU MUST FOLLOW THIS PROTOCOL:**',
    '1. Search for the most recent meeting with the specified account using MCP tools',
    '2. Check the date of the meeting you find',
    '3. **IF the meeting is from TODAY** → Great, use that data to draft the email',
    '4. **IF the meeting is NOT from today (even yesterday)** → The user almost certainly had a meeting TODAY that has not synced yet. In this case:',
    '   - Do NOT draft based on the older meeting',
    '   - Draft referencing "your meeting today" or "your conversation today"',
    '   - Use the account context, key contacts, and deal status you DO have to write a relevant follow-up',
    '   - Add a note: "_Your meeting today has not fully synced yet. Reply with key discussion topics and I will make this draft more specific._"',
    '   - Use participants from the older meeting as likely attendees (CC candidates)',
    '5. **IF no meetings found at all** → Ask the user for details about the meeting',
    '',
    'NEVER draft a follow-up anchored on a meeting from 5+ days ago when the user asks for a followup — they mean TODAY.',
    '',
    '## STEP 1: FIND THE SPECIFIC MEETING',
    'Use Backstory MCP tools to find the most recent meeting/activity with this account. Look for:',
    '- Meeting notes, agenda items, or transcript summaries',
    '- Specific topics discussed, decisions made, action items agreed upon',
    '- Who attended and what each person contributed or committed to',
    '',
    '## STEP 2: EXTRACT MEETING-SPECIFIC CONTENT',
    'From the meeting data, identify:',
    '- What was actually discussed (not general deal context)',
    '- Specific commitments or action items from the meeting',
    '- Questions raised or concerns expressed',
    '- Next steps agreed upon during the meeting',
    '',
    '## STEP 3: DRAFT THE EMAIL ANCHORED ON THIS MEETING',
    'The email MUST reference specifics from this meeting — not general account/deal status.',
    '- Lead with what was discussed in THIS meeting',
    '- Action items should be things agreed to IN this meeting',
    '- Do NOT pad with generic deal context or pipeline status unless it was discussed',
    '',
    '**IF MEETING NOTES ARE THIN OR MISSING:**',
    'If you find the meeting but the notes/details are sparse:',
    '- Say so: add a note like "_I found your meeting from {date} but details were limited. Reply with key topics to make this draft more specific._"',
    '- Draft a shorter, more general follow-up rather than fabricating specifics',
    '- Do NOT invent discussion topics that are not in the meeting data',
    '',
    '**DATE AWARENESS — adjust your follow-up language based on when the meeting was:**',
    '- Same day: "Thanks for the conversation today"',
    '- Yesterday: "Thanks for the conversation yesterday"',
    '- 2-3 days ago: "I wanted to follow up on our conversation from {day}"',
    '- 4-7 days ago: "Circling back on our discussion last {day}" — keep it natural',
    '- 7+ days ago: "I wanted to revisit a few items from our meeting on {date}" — acknowledge the gap',
    '- NEVER use immediate-sounding language like "Thanks for the productive discussion" if the meeting was 2+ days ago',
    '',
    '**FORMAT YOUR RESPONSE like this (Slack mrkdwn):**',
    '',
    ':email: *Follow-up Draft — {Account Name}*',
    '',
    '*To:* {Name} ({email@company.com}) — ALWAYS include email addresses. Use Backstory MCP to look up contact emails. If you cannot find an email, still include the name.',
    '*CC:* {Other meeting participants with emails — include internal team and external contacts}',
    '*Subject:* {concise subject line}',
    '',
    '---',
    '{email body — professional, concise, references specific discussion points}',
    '---',
    '',
    '_Reply in this thread to adjust the tone, add details, or ask me to revise._',
    '',
    '**RULES:**',
    '- Draft should be 150-250 words — concise and professional',
    '- Reference specific topics from THIS meeting — not general account activity',
    '- Do NOT fabricate meeting topics. Only reference what you found in the meeting data.',
    '- Include a clear next step or call to action',
    '- Match the tone to ' + repName + "'s communication style if you have context",
    '- Use the account contact names, not generic "team"',
    '- If no meetings at all are found for the account, ask the user for details',
    '- Keep the Slack message under 3000 characters total',
    '- Do NOT use ### headers — use *bold* for labels',
    '- ALWAYS sign the email as ' + repName + '. Do NOT sign as the account owner or AE — the person requesting the draft is ' + repName + '.',
    commandsBlock,
  ].join('\n');

} else {
  // ── General DM conversation prompt (existing behavior) ──
  systemPrompt = [
    'You are ' + assistantName + ', a personal sales assistant for ' + repName + '. You work exclusively for them.',
    '',
    'Your personality: ' + assistantPersona,
    '',
    'You have access to Backstory MCP tools which give you CRM data, account activity, opportunity details, engagement scores, and communication summaries.',
    '',
    '**INSTRUCTIONS:**',
    '- Use the Backstory MCP tools to answer the user\'s question with real data.',
    '- Be concise and actionable — this response will be posted in Slack.',
    '- Format your response using Slack markdown: *bold*, _italic_, `code`.',
    '- Use bullet points sparingly and keep them short.',
    '- If the question is about a specific account or opportunity, include key metrics (engagement level, amount, stage, etc.).',
    '- If you can\'t find the requested data, say so clearly rather than guessing.',
    '- Keep your total response under 3000 characters so it displays well in Slack.',
    '- Do NOT use headers with ### or ** section headers ** — just use *bold* for emphasis.',
    '- End with a brief actionable recommendation when relevant.',
    commandsBlock,
  ].join('\n');
}

const thinkingText = ':hourglass_flowing_sand: Thinking...';

return [{
  json: {
    systemPrompt,
    userMessage: routeData.text,
    channelId: routeData.channelId,
    userId: routeData.userId,
    assistantName,
    assistantEmoji,
    thinkingText,
    dbUserId: routeData.dbUserId,
    organizationId: routeData.organizationId,
  }
}];

const buildData = $('Build DM System Prompt').first().json;
const agentOutput = $('DM Conversation Agent').first().json.output || $('DM Conversation Agent').first().json.text || '';
const thinkingTs = $('DM Post Thinking').first().json.ts || '';

const agentConfig = {
  systemPrompt: buildData.systemPrompt,
  model: 'claude-sonnet-4-5-20250929',
  mcpEndpoint: 'https://mcp.people.ai/mcp',
  assistantName: buildData.assistantName,
  assistantEmoji: buildData.assistantEmoji,
};

const expiresAt = new Date(Date.now() + 4 * 60 * 60 * 1000).toISOString();

return [{
  json: {
    organizationId: buildData.organizationId,
    userId: buildData.dbUserId,
    channelId: buildData.channelId,
    threadTs: thinkingTs,
    workflowType: 'dm_conversation',
    agentConfig: agentConfig,
    expiresAt: expiresAt,
    userMessage: buildData.userMessage,
    assistantMessage: agentOutput,
  }
}];

