// If the agent output looks like an email draft, add a mailto button.
// Otherwise pass through unchanged for general DM responses.
const output = $json.output || $json.text || '';
const promptData = $('Build DM System Prompt').first().json;

const toMatch = output.match(/\*To:\*\s*(.+)/i);
const ccMatch = output.match(/\*CC:\*\s*(.+)/i);
const subjectMatch = output.match(/\*Subject:\*\s*(.+)/i);

// Not an email draft — pass through as plain text
if (!toMatch || !subjectMatch) {
  return [{ json: { ...($json), isDraft: false, blocks: null, fallbackText: output } }];
}

// Extract email from "Name (Title) <email>" or plain email
function extractEmail(line) {
  const angleMatch = line.match(/<([^>]+@[^>]+)>/);
  if (angleMatch) return angleMatch[1].trim();
  const parenMatch = line.match(/\(([^)]+@[^)]+)\)/);
  if (parenMatch) return parenMatch[1].trim();
  const plainMatch = line.match(/[\w.+-]+@[\w.-]+\.\w+/);
  if (plainMatch) return plainMatch[0].trim();
  return '';
}

const toEmail = extractEmail(toMatch[1]);
// Extract all emails from a line (for CC with multiple recipients)
function extractAllEmails(line) {
  const emails = [];
  const regex = /[\w.+-]+@[\w.-]+\.\w+/g;
  let m;
  while ((m = regex.exec(line)) !== null) {
    emails.push(m[0].trim());
  }
  return emails.join(',');
}
const ccEmail = ccMatch ? extractAllEmails(ccMatch[1]) : '';
const subject = subjectMatch[1].trim();

// Extract email body between the --- dividers (after Subject, before trailing ---)
let body = '';
if (subjectMatch) {
  const startIdx = output.indexOf(subjectMatch[0]) + subjectMatch[0].length;
  let afterSubject = output.substring(startIdx);

  // The email body is typically wrapped in --- dividers
  // Find the opening --- after subject
  const openDivider = afterSubject.indexOf('---');
  if (openDivider > -1) {
    const bodyStart = openDivider + 3;
    // Find the closing --- after the body
    const closeDivider = afterSubject.indexOf('\n---', bodyStart);
    if (closeDivider > -1) {
      body = afterSubject.substring(bodyStart, closeDivider).trim();
    } else {
      // No closing divider — use end markers as fallback
      body = afterSubject.substring(bodyStart).trim();
    }
  } else {
    // No dividers at all — take everything after subject
    body = afterSubject.trim();
  }

  // Trim at any Slack UI chrome that leaked through
  const uiMarkers = [
    '\n_Reply in this thread',
    '\n_Reply to adjust',
    '\n:warning:',
    '\n\u26a0',
    '\n*Next Steps',
  ];
  for (const marker of uiMarkers) {
    const idx = body.indexOf(marker);
    if (idx > -1) body = body.substring(0, idx).trim();
  }

  // Clean up any remaining --- at start/end
  body = body.replace(/^---\s*/, '').replace(/\s*---$/, '').trim();
}

// Strip Slack mrkdwn for plain-text email
const plainBody = body
  .replace(/\*\*([^*]+)\*\*/g, '$1')  // **double bold** (Markdown)
  .replace(/\*([^*]+)\*/g, '$1')       // *single bold* (Slack mrkdwn)
  .replace(/_([^_]+)_/g, '$1')          // _italic_
  .replace(/~([^~]+)~/g, '$1')          // ~strikethrough~
  .replace(/:[a-z0-9_+-]+:/g, '')       // :emoji: codes
  .replace(/•/g, '-')                    // bullet chars
  .replace(/- \*\*/g, '- ')             // leftover bold after bullets
  .replace(/\*\*$/gm, '')               // trailing bold markers
  .replace(/\n{3,}/g, '\n\n')           // excess newlines
  .trim();

// Build Gmail compose deep link
let composeUrl = '';
if (toEmail || subject) {
  const params = ['view=cm', 'fs=1'];
  if (toEmail) params.push('to=' + encodeURIComponent(toEmail));
  if (ccEmail) params.push('cc=' + encodeURIComponent(ccEmail));
  if (subject) params.push('su=' + encodeURIComponent(subject));
  if (plainBody) params.push('body=' + encodeURIComponent(plainBody));
  composeUrl = 'https://mail.google.com/mail/?' + params.join('&');
}

// Truncate if too long (browser URL limit ~8000 chars for Chrome)
const MAX_URL = 7500;
if (composeUrl.length > MAX_URL) {
  const truncBody = plainBody.substring(0, 2000) + '\n\n[... see full draft in Slack thread]';
  const params2 = ['view=cm', 'fs=1'];
  if (toEmail) params2.push('to=' + encodeURIComponent(toEmail));
  if (ccEmail) params2.push('cc=' + encodeURIComponent(ccEmail));
  if (subject) params2.push('su=' + encodeURIComponent(subject));
  params2.push('body=' + encodeURIComponent(truncBody));
  composeUrl = 'https://mail.google.com/mail/?' + params2.join('&');
}

// Build Block Kit
const blocks = [
  { type: "section", text: { type: "mrkdwn", text: output.substring(0, 2999) } }
];

if (composeUrl) {
  blocks.push({
    type: "actions",
    elements: [{
      type: "button",
      text: { type: "plain_text", text: ":email: Open in Gmail", emoji: true },
      url: composeUrl,
      style: "primary"
    }]
  });
}

return [{ json: { ...($json), isDraft: true, blocks: JSON.stringify(blocks), fallbackText: output, composeUrl } }];

// Build query for today's meetings (last 24h to catch late ones)
const now = Date.now();
const twentyFourHoursAgo = now - 24 * 60 * 60 * 1000;

const query = {
  object: "activity",
  filter: {
    "$and": [
      { attribute: { slug: "ootb_activity_type" }, clause: { "$eq": "meeting" } },
      { attribute: { slug: "ootb_activity_external" }, clause: { "$eq": true } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$gte": twentyFourHoursAgo } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$lte": now } }
    ]
  },
  columns: [
    { slug: "ootb_activity_uid" },
    { slug: "ootb_activity_timestamp" },
    { slug: "ootb_activity_subject" },
    { slug: "ootb_activity_account_name" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_email" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_name" }
  ],
  sort: [{ attribute: { slug: "ootb_activity_timestamp" }, direction: "desc" }]
};

return [{ json: { ...($input.first().json), meetingQuery: JSON.stringify(query) } }];

const data = $('Route by State').first().json;
const text = (data.text || '').trim();

// Strip command keywords to find account name
const accountArg = text
  .replace(/\b(recap|recaps|meeting\s+recap|meeting\s+recaps|my|the|a|for|with|about|on|please)\b/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!accountArg) {
  return [{ json: { ...data, hasAccount: false, responseText: 'What account should I recap? Try: `recap Redis` or `recap AMD`' } }];
}

const ur = data.userRecord || {};
const repName = (ur.email || '').split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, c => c.toUpperCase()) || 'Rep';
const assistantPersona = ur.assistant_persona || 'direct, action-oriented, and conversational';

return [{ json: {
  ...data,
  hasAccount: true,
  accountArg,
  repName,
  assistantPersona,
} }];

// Build Backstory activity export query for meetings in last 7 days
const data = $('Prepare Recap Input').first().json;
const now = Date.now();
const sevenDaysAgo = now - 7 * 24 * 60 * 60 * 1000;

const query = {
  object: "activity",
  filter: {
    "$and": [
      { attribute: { slug: "ootb_activity_type" }, clause: { "$eq": "meeting" } },
      { attribute: { slug: "ootb_activity_external" }, clause: { "$eq": true } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$gte": sevenDaysAgo } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$lte": now } }
    ]
  },
  columns: [
    { slug: "ootb_activity_uid" },
    { slug: "ootb_activity_timestamp" },
    { slug: "ootb_activity_subject" },
    { slug: "ootb_activity_originator" },
    { slug: "ootb_activity_account_name" },
    { slug: "ootb_activity_opportunity_name" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_email" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_name" }
  ],
  sort: [{ attribute: { slug: "ootb_activity_timestamp" }, direction: "desc" }]
};

return [{ json: { meetingQuery: JSON.stringify(query) } }];

// Parse CSV, find most recent meeting matching the account name
const prepData = $('Prepare Recap Input').first().json;
const accountArg = (prepData.accountArg || '').toLowerCase();
const raw = $('Recap Fetch Meetings').first().json.data || '';

if (!raw || raw.trim().length === 0) {
  return [{ json: { ...prepData, hasMeeting: false, responseText: "I couldn't find any recent meetings with *" + prepData.accountArg + "* in the last 7 days." } }];
}

const lines = raw.split('\n');
if (lines.length < 2) {
  return [{ json: { ...prepData, hasMeeting: false, responseText: "I couldn't find any recent meetings with *" + prepData.accountArg + "* in the last 7 days." } }];
}

// Parse CSV header
const headerLine = lines[0];
const headers = [];
let field = '';
let inQuotes = false;
for (let i = 0; i < headerLine.length; i++) {
  const c = headerLine[i];
  if (c === '"') { inQuotes = !inQuotes; }
  else if (c === ',' && !inQuotes) { headers.push(field.trim()); field = ''; }
  else { field += c; }
}
headers.push(field.trim());

function parseCSVRow(line) {
  const fields = [];
  let f = '';
  let q = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') {
      if (q && i + 1 < line.length && line[i + 1] === '"') { f += '"'; i++; }
      else { q = !q; }
    } else if (c === ',' && !q) { fields.push(f.trim()); f = ''; }
    else { f += c; }
  }
  fields.push(f.trim());
  return fields;
}

function getVal(row, ...names) {
  for (const name of names) {
    const idx = headers.findIndex(h => h.toLowerCase().includes(name.toLowerCase()));
    if (idx >= 0 && row[idx]) return row[idx];
  }
  return '';
}

function parseList(val) {
  if (!val) return [];
  return val.replace(/^\[/, '').replace(/\]$/, '').trim()
    .split(';').map(s => s.trim()).filter(Boolean);
}

// Find meetings matching account name (case-insensitive partial match)
let bestMatch = null;
let bestTs = 0;

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const row = parseCSVRow(lines[i]);

  const acctName = getVal(row, 'Account Name', 'Account');
  if (!acctName || !acctName.toLowerCase().includes(accountArg)) continue;

  const tsRaw = getVal(row, 'Activity date', 'date', 'timestamp');
  let tsMs = 0;
  if (tsRaw) {
    const num = Number(tsRaw);
    if (!isNaN(num) && num > 1e12) { tsMs = num; }
    else {
      const parsed = new Date(tsRaw);
      if (!isNaN(parsed.getTime())) tsMs = parsed.getTime();
    }
  }
  if (!tsMs) continue;

  // Most recent meeting wins
  if (tsMs > bestTs) {
    bestTs = tsMs;
    const activityUid = getVal(row, 'Activity') || '';
    const participantEmails = parseList(getVal(row, 'Participants (Email)', 'Participants'));
    const participantNames = parseList(getVal(row, 'Participants (Name)'));
    const dt = new Date(tsMs);
    const dayStr = dt.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
    const timeStr = dt.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/Los_Angeles' });

    bestMatch = {
      activityUid,
      timestamp: tsMs,
      subject: getVal(row, 'Subject'),
      accountName: acctName,
      accountId: '',
      opportunityName: getVal(row, 'Opportunity Name', 'Opportunity'),
      participants: participantNames.length > 0 ? participantNames.join('; ') : participantEmails.join('; '),
      participantEmails,
      participantNames,
      dayStr,
      timeStr,
    };
  }
}

if (!bestMatch) {
  return [{ json: { ...prepData, hasMeeting: false, responseText: "I couldn't find a recent meeting with *" + prepData.accountArg + "* in the last 7 days." } }];
}

return [{ json: { ...prepData, hasMeeting: true, meeting: bestMatch } }];

// Build recap context for the agent
const data = $('Recap Parse Meetings').first().json;
const m = data.meeting;
const repName = data.repName || 'Rep';
const assistantName = data.assistantName || 'Aria';
const assistantEmoji = data.assistantEmoji || ':robot_face:';
const assistantPersona = data.assistantPersona || 'direct, action-oriented, and conversational';

const todayStr = new Date().toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});
const tz = 'America/Los_Angeles';

const systemPrompt = `You are ${assistantName}, a personal sales assistant for ${repName}.
Your personality: ${assistantPersona}

TODAY IS ${todayStr}. ${repName} is in ${tz}.

MEETING CONTEXT:
- Account: ${m.accountName}
- Subject: ${m.subject}
- Time: ${m.dayStr} ${m.timeStr}
- Participants: ${m.participants || 'Unknown'}
- Participant Emails: ${(m.participantEmails || []).join('; ') || 'Unknown'}

Use Backstory MCP tools to research this meeting:
1. Find the meeting transcript, notes, topics discussed, and action items
2. Look up participant roles and recent engagement history
3. Check the related opportunity status if one exists
4. Get recent account activity for context

Generate a structured meeting recap as a JSON object with this exact shape:
{
  "summary": "2-3 sentence recap of what was discussed and key outcomes",
  "sentiment": "positive|neutral|negative|mixed",
  "sentiment_signal": "one sentence explaining the sentiment",
  "tasks": [
    {
      "description": "specific action item from the meeting",
      "owner": "MUST be an internal Backstory employee — never assign to external/customer contacts",
      "owner_email": "email address of the internal owner from the Participant Emails list — match the owner name to their email",
      "assignee_role": "CSM, AE, SE, or AI — CSM for technical support, training, onboarding, implementation; AE for strategic, commercial, expansion, executive engagement; SE for sales engineering, technical scoping, demos; AI for AI innovation and executive initiatives",
      "duration_minutes": "estimated minutes (15, 30, 45, 60, 90, 120)",
      "due_hint": "timeframe suggestion",
      "task_category": "best match from: Discovery Meeting, Demo Meeting, Prospecting & Qualification, Solution Presentation & Demo, Commercials & Negotiation, Technical Scoping & Solutioning, Onboarding & Implementation, Account & Renewal Management, Expansion & Upsell, Customer Training, Internal Deal Support (Legal/Fin/Sec), Product & Engineering Inquiry, Strategic Account & Territory Planning, Sales Operations & Coaching"
    }
  ],
  "key_decisions": ["decision 1", "decision 2"],
  "follow_up_context": "context to enrich a follow-up email",
  "meeting_category": "best match from: Discovery Meeting, Demo Meeting, Proposal Meeting, Security Meeting, Procurement Meeting, Legal Meeting",
}


For each task, estimate the duration in minutes and assign the role (CSM or AE) based on the nature of the work.

TOOL CALL BUDGET: You have limited tool calls. After ~8 calls, produce your output.
If a tool returns no data, move on. Do not retry.

RULES:
- Extract REAL tasks mentioned in the meeting — do NOT fabricate
- If transcript data is limited, say so in the summary and provide what you can from account context
- Tasks must be specific and actionable ("Send pricing proposal to Mark by Friday" not "Follow up")
- Maximum 5 tasks
- Keep summary under 100 words
- Output ONLY the JSON object — no prose, no markdown fences

Based on the meeting content, select the single best-matching value for each category field. Use the exact picklist value string. If none fit well, use null.`;

const agentPrompt = `Generate a meeting recap for my ${m.subject} meeting with ${m.accountName}.` +
  (m.participants ? ` Participants: ${m.participants}.` : '') +
  ` Use Backstory MCP tools to find transcript data, topics, and action items.` +
  ` Output ONLY the JSON object.`;

const channelId = $('Prepare Recap Input').first().json.channelId || $('Prepare Recap Input').first().json.channel || '';

return [{ json: {
  ...data,
  channelId,
  systemPrompt,
  agentPrompt,
  assistantName,
  assistantEmoji,
  repName,
} }];

// Parse recap agent output into structured data
const agentOutput = $('Recap Agent OD').first().json.output || '';
const context = $('Recap Build Context').first().json;

let recap = {};
try {
  let jsonStr = agentOutput;
  const fenceMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenceMatch) jsonStr = fenceMatch[1];
  const objMatch = jsonStr.match(/\{[\s\S]*\}/);
  if (objMatch) jsonStr = objMatch[0];
  recap = JSON.parse(jsonStr);
} catch(e) {
  recap = {
    summary: agentOutput.substring(0, 500) || 'Meeting recap could not be generated.',
    sentiment: 'neutral',
    sentiment_signal: '',
    tasks: [],
    key_decisions: [],
    follow_up_context: ''
  };
}

const sentimentEmoji = {
  'positive': ':white_check_mark:',
  'neutral': ':large_blue_circle:',
  'negative': ':red_circle:',
  'mixed': ':warning:'
}[recap.sentiment] || ':large_blue_circle:';

return [{ json: {
  ...context,
  recap: {
    summary: recap.summary || '',
    sentiment: recap.sentiment || 'neutral',
    sentimentEmoji,
    sentimentSignal: recap.sentiment_signal || '',
    tasks: (recap.tasks || []).slice(0, 5).map(t => ({
      description: t.description || '',
      owner: t.owner || '',
      owner_email: t.owner_email || '',
      assignee_role: t.assignee_role || '',
      duration_minutes: t.duration_minutes || 30,
      due_hint: t.due_hint || '',
      task_category: t.task_category || '',
    })),
    keyDecisions: recap.key_decisions || [],
    followUpContext: recap.follow_up_context || '',
    meetingCategory: recap.meeting_category || null,
  }
}}];

const SKILL_REGISTRY = [
  { id: 'draft_email', label: 'Draft Email',
    keywords: ['send email', 'follow up', 'follow-up', 'email', 'reach out', 'share with', 'send to', 'write to', 'notify', 'update via email', 'loop in'],
    buttonText: ':email: Want me to draft that email?', actionId: 'task_assist_draft_email' },
  { id: 'presentation', label: 'Create Presentation',
    keywords: ['create deck', 'build slides', 'presentation', 'qbr', 'prepare deck', 'slide deck', 'google slides'],
    buttonText: ':bar_chart: Want me to build that deck?', actionId: 'task_assist_presentation' },
  { id: 'stakeholder_map', label: 'Stakeholder Map',
    keywords: ['map contacts', 'stakeholder', 'decision maker', 'identify contacts', 'org chart', 'key contacts', 'champion'],
    buttonText: ':busts_in_silhouette: Want me to map the stakeholders?', actionId: 'task_assist_stakeholders' },
  { id: 'meeting_prep', label: 'Meeting Prep',
    keywords: ['prepare for meeting', 'prep for call', 'research before', 'meeting brief', 'pre-meeting', 'talking points'],
    buttonText: ':clipboard: Want me to prep you for that meeting?', actionId: 'task_assist_meeting_prep' },
];

function matchTaskToSkill(taskSubject, taskDescription) {
  const text = (taskSubject + ' ' + (taskDescription || '')).toLowerCase();
  for (const skill of SKILL_REGISTRY) {
    for (const kw of skill.keywords) {
      if (text.includes(kw)) return skill;
    }
  }
  return null;
}

const data = $('Build Auto-Save OD').first().json;
const recap = data.recap;
const m = data.meeting;
const assistantName = data.assistantName || 'Aria';
const assistantEmoji = data.assistantEmoji || ':robot_face:';
const taskCount = data.taskCount || 0;

const subjectLine = m.subject || 'Customer Meeting';
const blocks = [];

// Header: account + time + subject
blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `:clipboard: *${m.accountName}* \u00b7 ${m.dayStr}, ${m.timeStr} \u2014 ${subjectLine}` }
});

// Tight confirmation line
const taskPart = taskCount > 0 ? ` \u00b7 ${taskCount} task${taskCount === 1 ? '' : 's'} created` : '';
blocks.push({
  type: "section",
  text: { type: "mrkdwn", text: `:white_check_mark: Saved to CRM${taskPart}` }
});

// Summary teaser — first sentence or first 120 chars
const summary = recap.summary || '';
if (summary) {
  let teaser = summary;
  const firstSentence = summary.match(/^[^.!?]+[.!?]/);
  if (firstSentence && firstSentence[0].length <= 150) {
    teaser = firstSentence[0];
  } else {
    teaser = summary.substring(0, 120);
    if (summary.length > 120) teaser += '...';
  }
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `\u{1f4ac} _"${teaser}"_` }
  });
}

// Primary action: Draft Follow-up
const truncContext = (recap.followUpContext || '').substring(0, 500);
const draftPayload = JSON.stringify({
  action: 'draft_followup',
  account_name: m.accountName,
  account_id: m.accountId || '',
  activity_uid: m.activityUid,
  meeting_subject: m.subject,
  participants: m.participants || '',
  follow_up_context: truncContext,
  user_id: data.userId,
  db_user_id: data.userId,
  slack_user_id: data.slackUserId,
  organization_id: data.organizationId || '',
  assistant_name: assistantName,
  assistant_emoji: assistantEmoji,
  rep_name: data.repName,
});

blocks.push({
  type: "actions",
  elements: [{
    type: "button",
    text: { type: "plain_text", text: ":email: Want me to draft your follow-up?", emoji: true },
    action_id: "recap_draft_followup",
    value: draftPayload
  }]
});

// Task Assist: keyword match freshly created tasks
const assistable = [];
for (const t of (recap.tasks || [])) {
  const skill = matchTaskToSkill(t.description, '');
  if (skill) {
    assistable.push({ task: t, skill });
  }
}

if (assistable.length > 0) {
  for (const a of assistable.slice(0, 3)) {
    blocks.push({
      type: "actions",
      elements: [{
        type: "button",
        text: { type: "plain_text", text: a.skill.buttonText, emoji: true },
        action_id: a.skill.actionId,
        value: JSON.stringify({
          action: 'task_assist',
          skill: a.skill.id,
          task_subject: a.task.description,
          account_name: m.accountName,
          account_id: m.accountId || '',
          user_id: data.userId,
          slack_user_id: data.slackUserId,
          organization_id: data.organizationId || '',
          assistant_name: assistantName,
          assistant_emoji: assistantEmoji,
          rep_name: data.repName,
        })
      }]
    });
  }
}

// Footer links as context block
blocks.push({
  type: "context",
  elements: [{
    type: "mrkdwn",
    text: ":date: <https://glass.people.ai/sheet/294e924a-d11a-46b7-a373-aae4182c4a61|My Events Today> \u00b7 :clipboard: <https://glass.people.ai/sheet/0250d214-84ba-48e4-b272-6839c03462f5|All Tasks Today>"
  }]
});

const promptText = `Meeting Recap \u2014 ${m.accountName}: ${subjectLine}`;

return [{ json: {
  ...data,
  blocks: JSON.stringify(blocks),
  promptText,
  assistantName,
  assistantEmoji,
  activityUids: [m.activityUid],
}}];

const data = $('Build Auto-Save OD').first().json;
