const blocks = [];
const sentLine = `${recap.sentimentEmoji} ${recap.sentimentSignal || recap.sentiment}`;
blocks.push({ type: "section", text: { type: "mrkdwn", text: `${sentLine}\n\n${recap.summary}` } });
blocks.push({ type: "divider" });

if (recap.keyDecisions && recap.keyDecisions.length > 0) {
  blocks.push({ type: "section", text: { type: "mrkdwn", text: `*Key Decisions*\n${recap.keyDecisions.map(d => `\u2022 ${d}`).join('\n')}` } });
  blocks.push({ type: "divider" });
}

if (recap.tasks && recap.tasks.length > 0) {
  const taskText = recap.tasks.map(t => {
    const roleBadge = t.assignee_role ? ` (${t.assignee_role})` : '';
    const durationBadge = t.duration_minutes ? ` \u00b7 ${t.duration_minutes} min` : '';
    return `\u2022 ${t.description}` + (t.owner ? ` \u2014 _${t.owner}_` + roleBadge : '') + durationBadge + (t.due_hint ? ` \u00b7 ${t.due_hint}` : '');
  }).join('\n');
  blocks.push({ type: "section", text: { type: "mrkdwn", text: `*Action Items* (saved to CRM)\n${taskText}` } });
}

if ((!recap.keyDecisions || recap.keyDecisions.length === 0) && (!recap.tasks || recap.tasks.length === 0)) {
  blocks.push({ type: "section", text: { type: "mrkdwn", text: "_No key decisions or action items were captured for this meeting._" } });
}

blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: "Tasks and recap saved to CRM \u2022 Use PeopleGlass to review or modify \u2022 Reply in this thread to discuss" }] });

return [{ json: { threadBlocks: JSON.stringify(blocks), threadTs: sendResult.ts, channelId: sendResult.channel, assistantName, assistantEmoji } }];

